try_catch.syntax:
{% try %}
  {% graphql result = 'query' %}
{% catch error %}
  Error: {{ error }}
{% endtry %}

liquid_doc.syntax:
{% doc %}
  @param {type} name - description
  @prompt what this partial does
  @example {% render 'partial', name: 'value' %}
{% enddoc %}

hash_literals.syntax:
{% assign my_hash = {} %}
{% assign my_hash = { "name": "John", "age": 30 } %}
{% assign nested = { "user": { "name": "John" }, "roles": ["admin"] } %}

array_literals.syntax:
{% assign arr = [] %}
{% assign arr = ["apple", "banana", "cherry"] %}
{% assign mixed = [1, "two", true, null] %}

assign_bracket_dot.syntax:
{% assign hash["greeting"] = "hello" %}
{% assign hash.farewell = "goodbye" %}
{% assign hash["nested"]["key"] = "value" %}

array_append_operator.syntax:
{% assign my_array = [] %}
{% assign my_array << "first" %}
{% assign my_array << "second" %}

parse_json_deprecation.syntax:
Old: {% parse_json obj %}{"key": "value"}{% endparse_json %}
New: {% assign obj = { "key": "value" } %}

Old: {% parse_json arr %}["a", "b"]{% endparse_json %}
New: {% assign arr = ["a", "b"] %}

hash_assign_deprecation.syntax:
Old: {% hash_assign my_hash["key"] = "value" %}
New: {% assign my_hash["key"] = "value" %}

Old: {% hash_assign my_hash["key"] = "value" %}
New: {% assign my_hash.key = "value" %}
